import { Component, Fragment, h, Prop, Element, EventEmitter, Event, Listen, State } from '@stencil/core';
import { customTwMerge, generateRandId } from '../../utils/utils';
import { getNavItemLinkRel } from '../../utils/nav-item-link';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { getColorClass, getContainerClass, getLabelClass } from './wdpr-nav-item-small.utils';
import { NavItemClickDetail, NavItemSmallVariant } from './wdpr-nav-item-small.model';

@Component({
  tag: 'wdpr-nav-item-small',
  shadow: true,
})
export class WdprNavItemSmall {
  @Element() el: HTMLWdprNavItemSmallElement;

  @State() _internalId: string;
  @State() _isTwoLineClamp: boolean = false;

  @Prop() label!: string;
  @Prop({ reflect: true }) variant?: NavItemSmallVariant = 'label';
  @Prop({ reflect: true }) disabled?: boolean = false;
  @Prop({ reflect: true }) inverse?: boolean = false;
  @Prop({ reflect: true }) allowBoldText?: boolean = false;
  @Prop({ reflect: true }) showNotificationBadge?: boolean = false;
  @Prop() notificationNumber?: number = 0;
  @Prop() itemId?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;
  @Prop({ reflect: true }) href?: string;
  @Prop({ reflect: true }) target?: string;
  @Prop({ reflect: true }) rel?: string;

  @Event() wdprNavItemSmallClick: EventEmitter<NavItemClickDetail>;

  private _leadingSlot: HTMLSlotElement;
  private _trailingSlot: HTMLSlotElement;
  private _labelElement?: HTMLSpanElement;
  private _resizeObserver?: ResizeObserver;

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  @Listen('window:resize')
  handleWindowResize() {
    this._updateClampState();
  }

  componentWillLoad() {
    this._updateSlots();
    this._internalId = this.itemId || `wdpr-nav-item-small-${generateRandId()}`;
  }

  componentDidLoad() {
    this._updateClampState();

    if (typeof ResizeObserver !== 'undefined') {
      this._resizeObserver = new ResizeObserver(() => this._updateClampState());
      this._resizeObserver.observe(this.el);
      if (this._labelElement) {
        this._resizeObserver.observe(this._labelElement);
      }
    }
  }

  componentDidRender() {
    this._updateClampState();
  }

  disconnectedCallback() {
    this._resizeObserver?.disconnect();
  }

  private get _labelClass(): string {
    return getLabelClass(this._colorClass, this.allowBoldText);
  }

  private get _containerClass(): string {
    return getContainerClass(this.variant, this.inverse);
  }

  private get _contentAlignmentClass(): string {
    return this._isTwoLineClamp ? 'items-start' : 'items-center';
  }

  private get _colorClass(): string {
    return getColorClass(this.disabled, this.inverse);
  }

  private get _paddingClass(): string {
    if (this.variant === 'label-icon' && this._isTwoLineClamp) {
      return '';
    }

    return ['label-icon', 'icon-avatar-aligned'].includes(this.variant) ? '-mt-025' : '';
  }

  private get _trailingAlignmentOffsetClass(): string {
    return '-mt-025';
  }

  private get _trailingSectionAlignmentClass(): string {
    return this._isTwoLineClamp ? 'self-start' : '';
  }

  private get _sideAlignmentClass(): string {
    return this._isTwoLineClamp ? 'self-start' : '';
  }

  private get labelAvatarAligned(): string {
    return this.variant === 'icon-avatar-aligned' ? 'px-075 ml-075' : '';
  }

  private get _accessibleLabel(): string {
    return this.a11yLabel || this.label;
  }

  private get _isNavLink(): boolean {
    return Boolean(this.href?.trim()) && !this.disabled;
  }

  private get _anchorClass(): string {
    return customTwMerge(this._containerClass, 'no-underline');
  }

  private _emitClick() {
    this.wdprNavItemSmallClick.emit(this._internalId);
  }

  private _onItemInteraction = (ev: MouseEvent | KeyboardEvent) => {
    ev.preventDefault();
    if (this.disabled) return;

    this._emitClick();
  };

  private _onItemKeyDown = (ev: KeyboardEvent) => {
    if (ev.key === KEYBOARD_KEYS.ENTER || ev.key === KEYBOARD_KEYS.SPACE) {
      this._onItemInteraction(ev);
    }
  };

  private _onLinkClick = () => {
    if (this.disabled) return;
    this._emitClick();
  };

  private _updateSlots = () => {
    this._leadingSlot = this.el.querySelector('[slot="leading-icon"]');
    this._trailingSlot = this.el.querySelector('[slot="trailing-icon"]');
  };

  private _updateClampState = () => {
    if (!this._labelElement || typeof window === 'undefined') return;

    // keep explicit calculation to not hardcode the line height value
    const lineHeight = Number.parseFloat(window.getComputedStyle(this._labelElement).lineHeight);

    const isTwoLineClamp = this._labelElement.scrollHeight > lineHeight * 1.5;

    if (isTwoLineClamp !== this._isTwoLineClamp) {
      this._isTwoLineClamp = isTwoLineClamp;
    }
  };

  render() {
    const body = (
      <Fragment>
        <section class={`flex min-w-0 flex-1 gap-100 ${this._contentAlignmentClass}`}>
          {this._leadingSlot && (
            <div class={`shrink-0 flex items-center ${this._paddingClass} ${this.labelAvatarAligned} ${this._colorClass}`}>
              <slot name="leading-icon" onSlotchange={this._updateSlots}></slot>
            </div>
          )}

          <span class={this._labelClass} ref={el => (this._labelElement = el as HTMLSpanElement)}>
            {this.label}
          </span>
        </section>

        <section class={`flex shrink-0 ${this._trailingSectionAlignmentClass} ${this._trailingAlignmentOffsetClass} ${this._contentAlignmentClass}`}>
          {this.showNotificationBadge && (
            <span class={`flex items-center ${this._sideAlignmentClass} px-075`}>
              <wdpr-notification-indicator size="small" number={this.notificationNumber} decorative />
            </span>
          )}

          {this._trailingSlot && (
            <div class={`flex items-center ${this._sideAlignmentClass} ${this._colorClass}`}>
              <slot name="trailing-icon" onSlotchange={this._updateSlots}></slot>
            </div>
          )}
        </section>
      </Fragment>
    );

    if (this._isNavLink) {
      return (
        <a
          class={this._anchorClass}
          href={this.href!.trim()}
          id={this._internalId}
          aria-label={this._accessibleLabel}
          target={this.target}
          rel={getNavItemLinkRel(this.target, this.rel)}
          onClick={this._onLinkClick}
        >
          {body}
        </a>
      );
    }

    return (
      <div
        tabIndex={this.disabled ? -1 : 0}
        class={this._containerClass}
        id={this._internalId}
        role="button"
        aria-disabled={this.disabled ? 'true' : undefined}
        aria-label={this._accessibleLabel}
        onClick={this._onItemInteraction}
        onKeyDown={this._onItemKeyDown}
      >
        {body}
      </div>
    );
  }
}
